
import { initializeApp, getApps, App } from 'firebase-admin/app';

// IMPORTANT: DO NOT EXPORT the service account credentials.
// This is a placeholder and will be populated by the build environment.
const serviceAccount = process.env.FIREBASE_SERVICE_ACCOUNT
  ? JSON.parse(process.env.FIREBASE_SERVICE_ACCOUNT)
  : undefined;

/**
 * Initializes and returns the Firebase Admin App instance, ensuring it's a singleton.
 * This function is safe to call multiple times.
 */
export function initializeAdminApp(): App {
  // If the default app is not already initialized, initialize it.
  if (!getApps().length) {
    if (!serviceAccount) {
        throw new Error('FIREBASE_SERVICE_ACCOUNT environment variable not set. Cannot initialize Firebase Admin SDK.');
    }
    return initializeApp({
      credential: {
        projectId: serviceAccount.project_id,
        clientEmail: serviceAccount.client_email,
        privateKey: serviceAccount.private_key,
      },
    });
  }
  
  // Return the already initialized default app.
  return getApps()[0];
}
