'use server';

import { getAuth } from 'firebase-admin/auth';
import { initializeAdminApp } from '@/firebase/admin';

/**
 * Sets the 'admin' custom claim for a user by their email.
 * This should only be callable by an existing admin.
 * @param email The email of the user to grant admin privileges.
 */
export async function grantAdminRole(email: string): Promise<{ success: boolean; message: string }> {
  try {
    // Ensure the admin app is initialized
    initializeAdminApp();
    const adminAuth = getAuth();
    
    // Get the user by email
    const user = await adminAuth.getUserByEmail(email);
    
    // Set the custom claim
    await adminAuth.setCustomUserClaims(user.uid, { admin: true });

    return { success: true, message: `Successfully granted admin role to ${email}.` };
  } catch (error: any) {
    console.error('Error granting admin role:', error);
    return { success: false, message: error.message || 'An unexpected error occurred.' };
  }
}
